import { CSSResult, html } from 'lit';
import { property } from 'lit/decorators.js';
import { classMap } from 'lit/directives/class-map.js';
import { unsafeHTML } from 'lit/directives/unsafe-html.js';
import { marked } from 'marked';
import styles from './markdown.style.js';
import XUIElement from '../../internal/abstract.js';

type MarkdownMode = 'preview' | 'edit' | 'split';

let _markdownConfigured = false;

export default class XMarkdown extends XUIElement {
  static styles: CSSResult = styles;

  static defaultOptions = {
    mode: 'preview' as MarkdownMode,
    readOnly: false,
    lineNumbers: true,
    autoLoad: true,
    /** Markdown 资源文件请求的固定前缀，系统平台通过该前缀拦截并处理 Markdown 资源请求。 */
    resPrefix: '',
    /** 保存 Markdown 内容的 URL，设置后工具栏显示保存按钮。 */
    saveUrl: '',
  };

  /** Markdown 文本内容 */
  @property({ type: String }) content: string = '';

  /** 远程 Markdown 文件 URL */
  @property({ type: String }) url: string = '';

  /** 显示模式：preview | edit | split */
  @property({ type: String }) mode: MarkdownMode = 'preview';

  /** 加载状态 */
  @property({ type: Boolean, reflect: true }) loading: boolean = false;

  /** 加载错误信息 */
  @property({ type: String }) loadError: string = '';

  /** 保存状态 */
  @property({ type: Boolean }) saving: boolean = false;

  initialize(): void {
    super.initialize();

    if (this.mode === 'preview' && this.options.mode && this.options.mode !== 'preview') {
      this.mode = this.options.mode;
    }

    if (this.url && this.options.autoLoad) {
      this.loadFromUrl(this.url);
    }
  }

  /**
   * 切换显示模式。
   * @param mode 'preview' | 'edit' | 'split'
   */
  setMode(mode: MarkdownMode): void {
    if (mode === 'edit' || mode === 'preview' || mode === 'split') {
      this.mode = mode;
    }
  }

  /**
   * 从 URL 加载 Markdown 内容。
   * @param url 资源地址
   */
  async loadFromUrl(url: string): Promise<void> {
    this.loading = true;
    this.loadError = '';
    try {
      const text = await this.fetchMarkdown(url);
      this.url = url;
      this.content = text;
      this.emit('x-markdown-load', { detail: { url, content: text } });
    } catch (err: any) {
      this.loadError = err.message || 'Unknown error loading markdown';
    } finally {
      this.loading = false;
    }
  }

  /** 判断 URL 是否为外部链接（http / https / data: / # 锚点）。 */
  private isExternalUrl(url: string): boolean {
    return /^(https?:)?\/\//i.test(url) || url.startsWith('data:') || url.startsWith('#');
  }

  /** 判断 URL 是否无需添加前缀：完整 href、绝对路径（以 / 开头）或已包含 resPrefix。 */
  private hasUriPrefix(url: string): boolean {
    return /^(https?:)?\/\//i.test(url) || url.startsWith('/') || /^[a-zA-Z]:[/\\]/.test(url) || (!!this.options.resPrefix && url.startsWith(this.options.resPrefix));
  }

  /**
   * 为 Markdown 中的资源引用 URL 添加固定前缀。
   * 处理相对路径，外部链接和已有前缀的 URL 不处理。
   * 生成的 URL 会去掉原有查询参数，附加当前窗口的查询参数。
   */
  private replaceUriPrefix(resourceUrl: string, basePath: string): string {
    if (!resourceUrl || this.isExternalUrl(resourceUrl) || this.hasUriPrefix(resourceUrl)) {
      return resourceUrl;
    }
    let path: string;
    // 纯相对路径（不以 /、盘符、协议开头）直接使用，不按 basePath 解析，避免路径重复
    if (resourceUrl.startsWith('./') || resourceUrl.startsWith('../') || (!resourceUrl.startsWith('/') && !/^(https?:)?\/\//i.test(resourceUrl) && !/^[a-zA-Z]:[/\\]/.test(resourceUrl))) {
      path = resourceUrl;
    } else {
      try {
        path = new URL(resourceUrl, new URL(basePath, window.location.origin)).pathname;
      } catch {
        path = resourceUrl.replace(/^\.?\//, '');
      }
    }
    // 去掉资源 URL 自带的查询参数，仅保留路径部分
    const q = path.indexOf('?');
    if (q > -1) path = path.substring(0, q);
    // 附加当前窗口的查询参数（兼容 hash 路由）
    const href = window.location.href;
    const qi = window.location.href.indexOf('?');
    const search = qi > -1 ? href.substring(qi) : '';
    return this.options.resPrefix + path.replace(/^\//, '') + search;
  }

  /** 重写 HTML 片段中的资源引用 URL（src / href），添加 Markdown 资源前缀。 */
  private rewriteResourceUrls(html: string, basePath: string): string {
    html = html.replace(/(src=)"([^"]+)"/gi, (_match, prefix, url) =>
      `${prefix}"${this.replaceUriPrefix(url, basePath)}"`);
    html = html.replace(/(href=)"([^"]+)"/gi, (_match, prefix, url) =>
      `${prefix}"${this.replaceUriPrefix(url, basePath)}"`);
    return html;
  }

  /** 解析 Markdown 内容为 HTML，若设置了 resPrefix 则将资源引用重写为带前缀的路径。 */
  private toHtml(content: string): string {
    const html = this.parseMarkdown(content);
    if (this.options.resPrefix) {
      return this.rewriteResourceUrls(html, this.url || '');
    }
    return html;
  }

  /**
   * 设置 Markdown 内容。
   * @param content Markdown 文本
   */
  loadContent(content: string): void {
    this.content = content;
    this.loadError = '';
  }

  private get$textarea(): HTMLTextAreaElement | null {
    return this.renderRoot.querySelector('.editor-textarea') as HTMLTextAreaElement | null;
  }

  private onEditInput(_e: Event): void {
    // 内容同步由 textarea 的 .value 绑定处理，此处仅发出事件
    const textarea = this.get$textarea();
    if (textarea) {
      this.emit('x-markdown-change', { detail: { content: textarea.value } });
    }
  }

  private onApply(): void {
    this.emit('x-markdown-change', { detail: { content: this.content, committed: true } });
  }

  /**
   * 保存 Markdown 内容到服务器。
   * 使用 FormData 格式 POST 到 x-options 中配置的 saveUrl。
   */
  private async onSave(): Promise<void> {
    const saveUrl = this.options.saveUrl;
    if (!saveUrl) return;

    this.saving = true;
    try {
      const formData = new FormData();
      formData.append('content', this.content);
      const response = await fetch(saveUrl, { method: 'POST', body: formData });
      if (!response.ok) {
        throw new Error(`Save failed: ${response.status} ${response.statusText}`);
      }
      this.emit('x-markdown-save', { detail: { content: this.content } });
    } catch (err: any) {
      this.emit('x-markdown-save-error', { detail: { error: err.message || 'Unknown error' } });
    } finally {
      this.saving = false;
    }
  }

  private renderToolbar() {
    const icEdit = html`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" width="14" height="14" fill="currentColor"><path d="M12.146.146a.5.5 0 0 1 .708 0l3 3a.5.5 0 0 1 0 .708l-10 10a.5.5 0 0 1-.168.11l-5 2a.5.5 0 0 1-.65-.65l2-5a.5.5 0 0 1 .11-.168l10-10zM11.207 2.5 13.5 4.793 14.793 3.5 12.5 1.207 11.207 2.5zm1.586 2.793L10.5 3 4 9.5 3.1 11.9l2.4-.8L11.793 5.5z"/></svg>`;
    const icView = html`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" width="14" height="14" fill="currentColor"><path d="M16 8s-3-5.5-8-5.5S0 8 0 8s3 5.5 8 5.5S16 8 16 8zM1.173 8a13 13 0 0 1 1.66-2.043C4.12 4.668 5.88 3.5 8 3.5s3.879 1.168 5.168 2.457A13 13 0 0 1 14.828 8a13 13 0 0 1-1.66 2.043C11.879 11.332 10.119 12.5 8 12.5s-3.879-1.168-5.168-2.457A13 13 0 0 1 1.172 8z"/><path d="M8 5.5a2.5 2.5 0 1 0 0 5 2.5 2.5 0 0 0 0-5zM4.5 8a3.5 3.5 0 1 1 7 0 3.5 3.5 0 0 1-7 0z"/></svg>`;
    const icSplit = html`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" width="14" height="14" fill="currentColor"><path d="M3 1h10a2 2 0 0 1 2 2v10a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V3a2 2 0 0 1 2-2zm0 1a1 1 0 0 0-1 1v10a1 1 0 0 0 1 1h4.5V2H3zm5.5 0v12H13a1 1 0 0 0 1-1V3a1 1 0 0 0-1-1H8.5z"/></svg>`;
    const icReload = html`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" width="14" height="14" fill="currentColor"><path fill-rule="evenodd" d="M8 3a5 5 0 1 0 4.546 2.914.5.5 0 0 1 .908-.417A6 6 0 1 1 8 2v1z"/><path d="M8 4.466V.534a.25.25 0 0 1 .41-.192l2.36 1.966c.12.1.12.284 0 .384L8.41 4.658A.25.25 0 0 1 8 4.466z"/></svg>`;
    const icSave = html`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" width="14" height="14" fill="currentColor"><path d="M2 1a1 1 0 0 0-1 1v12a1 1 0 0 0 1 1h12a1 1 0 0 0 1-1V4.414a1 1 0 0 0-.293-.707l-2.414-2.414A1 1 0 0 0 11.586 1H2zm0 1h1v4.5A1.5 1.5 0 0 0 4.5 8h5A1.5 1.5 0 0 0 11 6.5V2h.586L14 4.414V14H2V2zm2 0v4.5a.5.5 0 0 0 .5.5h5a.5.5 0 0 0 .5-.5V2H4zm2 10.5V11h4v1.5a.5.5 0 0 1-.5.5h-3a.5.5 0 0 1-.5-.5z"/></svg>`;

    return html`
      <div class="toolbar">
        <slot name="toolbar"></slot>
        <div class="mode-toggle">
          <button class="${classMap({ active: this.mode === 'edit' })}"
            @click="${() => this.setMode('edit')}" title="编辑">
            ${icEdit}
          </button>
          <button class="${classMap({ active: this.mode === 'preview' })}"
            @click="${() => this.setMode('preview')}" title="预览">
            ${icView}
          </button>
          <button class="${classMap({ active: this.mode === 'split' })}"
            @click="${() => this.setMode('split')}" title="分屏">
            ${icSplit}
          </button>
        </div>
        ${this.url ? html`
          <button class="reload-btn" @click="${() => this.loadFromUrl(this.url)}" title="重新加载">
            ${icReload}
          </button>
        ` : ''}
        ${!this.options.readOnly && this.options.saveUrl ? html`
          <button class="save-btn" @click="${this.onSave}" ?disabled="${this.saving}" title="保存">
            ${icSave}
          </button>
        ` : ''}
      </div>
    `;
  }

  private renderPreview() {
    const htmlContent = this.toHtml(this.content);
    return html`
      <div class="preview-pane markdown-body">
        ${this.content ? unsafeHTML(htmlContent) : html`<span style="color:#999">暂无内容</span>`}
      </div>
    `;
  }

  private lineNumbersTemplate(): string {
    const lines = (this.content || '').split('\n').length;
    let result = '';
    for (let i = 1; i <= Math.max(lines, 1); i++) {
      result += `<span>${i}</span>`;
    }
    return result;
  }

  private renderEditor() {
    const readOnly = this.options.readOnly;
    return html`
      <div class="edit-pane">
        <div class="editor-wrapper">
          ${this.options.lineNumbers ? html`
            <div class="line-numbers" .innerHTML="${this.lineNumbersTemplate()}"></div>
          ` : ''}
          <textarea
            class="editor-textarea"
            .value="${this.content}"
            @input="${this.onEditInput}"
            ?readonly="${readOnly}"
            spellcheck="false"
          ></textarea>
        </div>
        ${!readOnly ? html`
          <button class="apply-btn" @click="${this.onApply}">应用</button>
        ` : ''}
      </div>
    `;
  }

  private renderSplit() {
    const htmlContent = this.toHtml(this.content);
    const readOnly = this.options.readOnly;
    return html`
      <div class="split-container">
        <div class="split-edit">
          <div class="editor-wrapper">
            ${this.options.lineNumbers ? html`
              <div class="line-numbers" .innerHTML="${this.lineNumbersTemplate()}"></div>
            ` : ''}
            <textarea
              class="editor-textarea"
              .value="${this.content}"
              @input="${this.onEditInput}"
              ?readonly="${readOnly}"
              spellcheck="false"
            ></textarea>
          </div>
        </div>
        <div class="split-divider"></div>
        <div class="split-preview markdown-body">
          ${this.content ? unsafeHTML(htmlContent) : html`<span style="color:#999">暂无内容</span>`}
        </div>
      </div>
    `;
  }

  render() {
    return html`
      <div class="x-root">
        ${this.renderToolbar()}
        <div class="x-body">
          ${this.loading ? html`<div class="loading-overlay">加载中...</div>` : ''}
          ${this.loadError ? html`<div class="load-error">${this.loadError}</div>` : ''}
          ${this.mode === 'preview' ? this.renderPreview() : ''}
          ${this.mode === 'edit' ? this.renderEditor() : ''}
          ${this.mode === 'split' ? this.renderSplit() : ''}
        </div>
      </div>
    `;
  }

  /**
   * 将 Markdown 文本解析为 HTML。
   * 自动规范化转义的换行符（\\n → \n）。
   */
  private parseMarkdown(content: string): string {
    if (!content) return '';
    if (!_markdownConfigured) {
      marked.setOptions({ breaks: true, gfm: true });
      _markdownConfigured = true;
    }
    const normalized = content.replace(/\\n/g, '\n');
    return (marked.parse(normalized) as string).trim();
  }

  /**
   * 从 URL 拉取 Markdown 内容。
   * @param url 资源地址
   * @return Markdown 文本
   * @throws 非 ok 响应时抛出异常
   */
  private async fetchMarkdown(url: string): Promise<string> {
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Failed to load markdown: ${response.status} ${response.statusText}`);
    }
    return response.text();
  }
}
