import { css } from 'lit';
import componentStyles from '../../styles/component.styles';

export default css`
  ${componentStyles}
  :host {
    position: absolute;
  }
  .x-root {
    display: flex;
    position: absolute;
    flex-direction: column;
    inset: 0px;
  }
  .x-root > header {
    position: relative;
    width: 100%;
  }
  .x-root > main {
    flex: 1;
    display: flex;
    position: relative;
    flex-direction: row;
  }
  .x-root > footer {
    position: relative;
    width: 100%;
  }
  .x-root > main > .east {
    position: relative;
  }
  .x-root > main > .center {
    flex: 1;
    height: 100%;
    position: relative;
  }
  .x-root > main > .west {
    position: relative;
  }
  .x-root .border {
    border: 1px solid #80cefc;
  }
`;
