import { css } from 'lit';
import componentStyles from '../../styles/component.styles';

export default css`
  ${componentStyles}
  .x-root {
    position: relative;
    overflow: hidden;
    padding-left: 2px;
    background-color: white;
  }
  .x-root.x-list-popup-active {
    overflow: visible;
  }
  .x-list {
    display: block;
    border: 1px solid #80cefc;
  }
  li {
    list-style: none;
  }
  :host > ul {
    padding: 0px;
    margin: 0px;
    font-size: 12px;
  }
  li > ul {
    padding-left: 20px;
    margin: 0px auto;
  }
  x-cell {
    height: 20px;
    padding-right: 5px;
  }
  x-cell::part(icon) {
    width: 16px;
    height: 16px;
  }
  x-cell::part(title) {
    font-style: normal;
    font-size: 12px;
    padding-left: 8px;
  }
  x-cell:hover {
    background: #e4fcf7;
  }
  .sp-line {
    position: absolute;
    left: 21px;
    top: 1px;
    bottom: 1px;
    width: 1px;
    background-color: #e7e7e7;
  }
  .expend, .collapse {
    display: flex;
  }
  .expend:before {
    margin: auto 0;
    content: url("data:image/svg+xml;charset=UTF-8,<svg xmlns='http://www.w3.org/2000/svg' width='15' height='15' viewBox='0 0 512 400'><polyline points='112 184 256 328 400 184' style='fill:none;stroke:gray;stroke-linecap:round;stroke-linejoin:round;stroke-width:48px'/></svg>");
  }
  .expend + ul {
    display: inherit;
  }
  .collapse:before {
    margin: auto 0;
    content: url("data:image/svg+xml;charset=UTF-8,<svg xmlns='http://www.w3.org/2000/svg' width='15' height='15' viewBox='0 0 512 400'><polyline points='184 112 328 256 184 400' style='fill:none;stroke:gray;stroke-linecap:round;stroke-linejoin:round;stroke-width:48px'/></svg>");
  }
  .collapse + ul {
    display: none;
  }
  .x-item-wrapper {
    position: relative;
  }
  .x-sub-arrow {
    position: absolute;
    right: 2px;
    top: 50%;
    transform: translateY(-50%);
    width: 12px;
    height: 12px;
    pointer-events: none;
    opacity: 0.6;
    font-style: normal;
  }
  .x-sub-arrow::before {
    font-family: FontAwesome;
    font-size: 10px;
    content: '\\f0da';
    color: #888;
  }
  .x-sub-menu-popup {
    position: absolute;
    top: 0;
    z-index: 1000;
    display: none;
    min-width: 120px;
    background: white;
    border: 1px solid #80cefc;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
  }
  .x-sub-menu-open {
    display: block;
  }
  .x-sub-menu-right {
    left: calc(100% - 1px);
  }
  .x-sub-menu-left {
    right: calc(100% - 1px);
  }
`;
