import { LitElement, PropertyValues, ReactiveController, ReactiveControllerHost } from 'lit';
import { property, state } from 'lit/decorators.js';
import { util } from './utils';

/**
 * 筛选出「必须携带 detail」的 CustomEvent 事件类型。
 *
 * 遍历 GlobalEventHandlersEventMap 中所有事件类型，通过多层条件类型判断：
 *   1. 该事件类型必须是 CustomEvent（泛型参数为 Record<PropertyKey, unknown>）
 *   2. 排除 detail 为 never 的 CustomEvent（即不需要 detail 的事件）
 *   3. 排除 detail 所有字段都可选的 CustomEvent（即 detail 可选的事件）
 *
 * 结果：只有 detail 至少包含一个必填字段的 CustomEvent 类型才会被保留，
 *       这类事件在调用 emit() 时必须传入 detail。
 */
type EventTypeIncDetail<T> = T extends keyof GlobalEventHandlersEventMap
  ? GlobalEventHandlersEventMap[T] extends CustomEvent<Record<PropertyKey, unknown>>
    ? GlobalEventHandlersEventMap[T] extends CustomEvent<Record<PropertyKey, never>>
      ? never
      : Partial<GlobalEventHandlersEventMap[T]['detail']> extends GlobalEventHandlersEventMap[T]['detail']
      ? never
      : T
    : never
  : never;

/**
 * 筛选出「不需要携带 detail」的 CustomEvent 事件类型。
 *
 * 与 EventTypeIncDetail 互补——保留以下三类事件：
 *   1. 非 CustomEvent 的普通事件（如 click、mouseover）
 *   2. detail 为 never 的 CustomEvent（明确不需要 detail）
 *   3. detail 所有字段都可选的 CustomEvent（detail 可传可不传）
 *
 * 结果：调用 emit() 时可以不传 detail 参数的事件类型。
 */
type EventTypeExcDetail<T> = T extends keyof GlobalEventHandlersEventMap
  ? GlobalEventHandlersEventMap[T] extends CustomEvent<Record<PropertyKey, unknown>>
    ? GlobalEventHandlersEventMap[T] extends CustomEvent<Record<PropertyKey, never>>
      ? T
      : Partial<GlobalEventHandlersEventMap[T]['detail']> extends GlobalEventHandlersEventMap[T]['detail']
      ? T
      : never
    : T
  : T;

/**
 * 必须携带 detail 的事件类型映射表。
 *
 * 将 EventTypeIncDetail 筛选出的事件类型映射为 { [事件名]: true } 的字面量对象类型，
 * 用于 emit() 重载签名中的类型约束——命中此映射的事件必须在调用时提供 detail。
 */
type EventTypesWithDetail = {
  [EventType in keyof GlobalEventHandlersEventMap as EventTypeIncDetail<EventType>]: true;
};

/**
 * 不需要携带 detail 的事件类型映射表。
 *
 * 将 EventTypeExcDetail 筛选出的事件类型映射为 { [事件名]: true }，
 * 用于 emit() 重载签名——命中此映射的事件调用时 detail 为可选。
 */
type EventTypesNotDetail = {
  [EventType in keyof GlobalEventHandlersEventMap as EventTypeExcDetail<EventType>]: true;
};

/**
 * 将对象类型 T 中的指定键 K 变为必填（去除 optional 修饰符）。
 *
 * 通过映射类型 { [P in K]-?: T[P] } 将 K 键的可选标记 `?` 移除，
 * 再与原始类型 T 做交叉（&），确保 K 键在结果类型中为 required。
 */
type WithRequired<T, K extends keyof T> = T & { [P in K]-?: T[P] };

/**
 * 推导 CustomEvent 构造选项类型（CustomEventInit），并根据事件类型决定 detail 是否必填。
 *
 * 判断逻辑：
 *   1. 普通事件（非 CustomEvent）→ CustomEventInit（detail 可选）
 *   2. detail 为 never 的 CustomEvent → CustomEventInit（detail 可选）
 *   3. detail 所有字段都可选的 CustomEvent → CustomEventInit（detail 可选）
 *   4. detail 至少有一个必填字段的 CustomEvent → WithRequired<CustomEventInit, 'detail'>（detail 必填）
 *
 * 这确保了 TypeScript 在调用 emit() 时能正确检查 detail 参数是否必须提供。
 */
type XEventInit<T> = T extends keyof GlobalEventHandlersEventMap
  ? GlobalEventHandlersEventMap[T] extends CustomEvent<Record<PropertyKey, unknown>>
    ? GlobalEventHandlersEventMap[T] extends CustomEvent<Record<PropertyKey, never>>
      ? CustomEventInit<GlobalEventHandlersEventMap[T]['detail']>
      : Partial<GlobalEventHandlersEventMap[T]['detail']> extends GlobalEventHandlersEventMap[T]['detail']
      ? CustomEventInit<GlobalEventHandlersEventMap[T]['detail']>
      : WithRequired<CustomEventInit<GlobalEventHandlersEventMap[T]['detail']>, 'detail'>
    : CustomEventInit
  : CustomEventInit;

/**
 * 推导 emit() 返回的 CustomEvent 具体类型。
 *
 * 如果 T 是标准事件名，则返回 GlobalEventHandlersEventMap 中对应的 CustomEvent 子类型；
 * 否则返回泛型的 CustomEvent<unknown>。
 */
type GetCustomEventType<T> = T extends keyof GlobalEventHandlersEventMap
  ? GlobalEventHandlersEventMap[T] extends CustomEvent<unknown>
    ? GlobalEventHandlersEventMap[T]
    : CustomEvent<unknown>
  : CustomEvent<unknown>;

/**
 * 有效事件类型映射的联合类型。
 *
 * 用于 emit() 重载签名的约束——传入的事件名必须至少命中
 * EventTypesWithDetail 或 EventTypesNotDetail 其中之一。
 */
type ValidEventTypeMap = EventTypesWithDetail | EventTypesNotDetail;

/**
 * 默认选项控制器。
 *
 * 实现 Lit 的 ReactiveController 接口，在宿主元素连接到 DOM 时执行初始化逻辑。
 * 当前为占位实现，后续可扩展为统一管理组件默认选项的生命周期。
 */
export class DefaultOptionsController implements ReactiveController {
  private host: ReactiveControllerHost;

  constructor(host: ReactiveControllerHost) {
    this.host = host;
    host.addController(this as ReactiveController);
  }

  /**
   * 宿主元素 connectedCallback 时由 Lit 自动调用。
   * 当前仅输出宿主引用，供调试使用。
   */
  hostConnected() {
    console.log(this.host);
  }
}

/**
 * attribute: HTML标签上的特性，可以理解为标签属性，它的值只能够是String类型，并且会自动添加同名DOM属性作为property的初始值；
 * property: DOM中的属性，是JavaScript里的对象，有同名attribute标签属性的property属性值的改变也并不会同步引起attribute标签属性值的改变；
 *
 * XUIElement 是所有 XUI 组件的抽象基类，继承自 LitElement，提供：
 *   - 类型安全的事件触发（emit）
 *   - 自定义元素注册（define）
 *   - 脚本执行（execScript）
 *   - 选项管理（getOption / setOption / hasOption）
 *   - 生命周期扩展（initialize / willUpdate）
 */
export default abstract class XUIElement extends LitElement {
  /**
   * 触发自定义事件（无需 detail 的重载）。
   *
   * 当事件类型命中 EventTypesNotDetail 映射时，detail 参数为可选。
   * 适用于普通 DOM 事件或 detail 全部可选/不需要的 CustomEvent。
   *
   * @param name - 事件名称，必须为 GlobalEventHandlersEventMap 中的合法类型
   * @param options - CustomEventInit 选项（detail 可选）
   * @returns 推导出的 CustomEvent 子类型实例
   */
  emit<T extends any & keyof EventTypesNotDetail>(name: EventTypeExcDetail<T>, options?: XEventInit<T> | undefined): GetCustomEventType<T>;

  /**
   * 触发自定义事件（实现）。
   *
   * 创建一个 CustomEvent 实例，设置 bubbles / cancelable / composed 均为 true，
   * 确保事件可以在 Shadow DOM 边界冒泡并被祖先元素捕获。
   * 通过 this.dispatchEvent() 同步派发事件。
   *
   * @param name - 事件名称
   * @param options - 自定义事件选项，会与默认的 { bubbles: true, cancelable: true, composed: true, detail: {} } 合并
   * @returns 派发的 CustomEvent 实例
   */
  emit<T extends any & keyof ValidEventTypeMap>(name: T, options?: XEventInit<T> | undefined) {
    const customEvent = new CustomEvent(name, {
      bubbles: true,
      cancelable: true,
      composed: true,
      detail: {},
      ...options,
    });

    this.dispatchEvent(customEvent);

    return customEvent as GetCustomEventType<T>;
  }

  /**
   * 注册自定义元素。
   *
   * 检查 customElements 注册表中是否已存在同名元素：
   *   - 不存在：创建构造函数的匿名子类并注册（避免直接注册原始构造函数）
   *   - 已存在：跳过注册（静默处理，不抛出异常）
   *
   * @param name - 自定义元素标签名（如 'x-layout'）
   * @param elementConstructor - 元素构造函数，默认值为调用者自身
   * @param options - ElementDefinitionOptions（如 extends 等）
   */
  static define(name: string, elementConstructor = this, options: ElementDefinitionOptions = {}) {
    const registeredConstructor = customElements.get(name) as CustomElementConstructor | typeof XUIElement;

    if (!registeredConstructor) {
      customElements.define(name, class extends elementConstructor {} as unknown as CustomElementConstructor, options);
      return;
    }
  }

  /**
   * 执行脚本字符串。
   *
   * 通过 Function 构造函数将字符串编译为函数，并绑定 this 为目标对象后执行。
   * 用于运行 HTML 属性中定义的内联脚本（如 x-script 或自定义事件属性）。
   *
   * @param target - 脚本中 this 的绑定目标
   * @param section - 待执行的 JavaScript 代码字符串，为 null 时跳过执行
   */
  static execScript(target: any, section: string | null) {
    if (section != null) {
      const execFunc = new Function(section);
      /** 绑定this为当前元素 */
      execFunc.bind(target)();
    }
  }

  static dependencies: Record<string, typeof XUIElement> = {};
  /** 自定义事件映射表：事件名 → CustomEvent 构造函数，在 connectedCallback 中自动绑定 DOM 属性事件 */
  static customEvents: Record<string, typeof CustomEvent<any>> = {};
  /** options 的默认值映射表，在 initialize() 中将未设置的选项填充为默认值 */
  static defaultOptions: Record<string, string | boolean | number | object> = {};

  @property() key?: string = '';
  @property() name?: string = '';
  /**
   * x-options 属性解析器。
   *
   * 将 HTML 属性字符串（格式如 "border:true,url:'/path'"）解析为 JavaScript 对象。
   * 通过 unsafeJson 包裹一层花括号后解析，实现类似 JSON 的松散键值对格式。
   */
  @property({
    attribute: 'x-options',
    converter: (value) => {
      const result = util.unsafeJson('{' + value + '}');
      if (result) return result;
    },
  })
  options: any = {};
  /** 组件绑定的业务数据，通过 setData / getData 存取 */
  @state() data: any = void 0;
  @property() icon: string = '';
  /** x-script 内联脚本，在 connectedCallback 时自动执行 */
  @property({ attribute: 'x-script' }) script?: string;
  /** 自定义事件 → 处理函数 的映射缓存，用于在 disconnectedCallback 时正确移除监听器 */
  private eventFunctionMap = new Map();

  constructor() {
    super();

    /** 根据dependencies定义预先注册依赖性组件 */
    Object.entries((this.constructor as typeof XUIElement).dependencies).forEach(([name, component]) => {
      (this.constructor as typeof XUIElement).define(name, component);
    });
  }

  /**
   * 获取组件绑定的业务数据。
   *
   * @returns 通过 setData() 设置的任意类型数据
   */
  getData() {
    return this.data;
  }

  /**
   * 设置组件绑定的业务数据。
   *
   * @param o - 任意类型的数据对象，通常为后端返回的实体数据
   */
  setData(o: any) {
    this.data = o;
  }

  /**
   * 获取完整的 options 对象。
   *
   * @returns 解析后的 options 键值对象
   */
  getOptions() {
    return this.options;
  }

  /**
   * 获取指定名称的选项值。
   *
   * @param name - 选项名（如 'border', 'url', 'park'）
   * @returns 选项值，如果 name 为空则返回 undefined
   */
  getOption(name: string): any {
    if (util.isBlank(name)) return;
    return this.options[name];
  }

  /**
   * 设置指定名称的选项值。
   *
   * 智能合并策略：
   *   - 如果已有值和传入值都是对象 → Object.assign 合并（保留未覆盖的旧字段）
   *   - 否则直接替换（字符串、数字、布尔值等基本类型）
   *
   * @param name - 选项名
   * @param value - 选项值
   */
  setOption(name: string, value: any) {
    const object = this.options[name];
    if (typeof object == 'object' && typeof value == 'object') {
      Object.assign(object, value);
    } else {
      this.options[name] = value;
    }
  }

  /**
   * 判断是否存在指定选项，并可检查选项值是否匹配给定候选值之一。
   *
   * @param name - 选项名
   * @param values - 可选的候选值列表，传入后只有当选项值与其中之一严格相等时才返回 true
   * @returns 选项存在（且匹配候选值）返回 true，否则 false
   */
  hasOption(name: string, ...values: any[]): boolean {
    if (this.options == void 0) return false;
    if (util.isBlank(name)) return false;

    if (name in this.options) {
      if (values && values.length > 0) {
        const value = this.options[name];
        for (const val of values) {
          if (value == val) return true;
        }
        return false;
      }
      return true;
    }
    return false;
  }

  /**
   * 将任意值安全转换为字符串。
   *
   * @param val - 待转换的值
   * @returns undefined / null → ''，字符串 → 原样返回，数字 → toString()，其他 → toString()
   */
  toS(val: any): string {
    if (val == void 0) return '';
    else if (typeof val === 'string') return val;
    else if (typeof val === 'number') return val.toString();
    return val.toString();
  }

  /**
   * 设置宿主元素的 CSS 样式。
   *
   * 通过 util.setStyle 将键值对应用到元素的 style 属性上。
   *
   * @param values - 样式键值对对象，如 { width: '100px', height: '50px' }
   */
  setHostStyle(values: any) {
    util.setStyle(this, values);
  }

  /**
   * 组件首次渲染前的初始化钩子。
   *
   * 将 defaultOptions 中定义的默认值写入 options：
   *   对于 defaultOptions 中的每个键，如果 options 中尚未设置该键，
   *   则使用默认值填充。这样可以确保组件的可选配置项始终有合理的回退值。
   */
  initialize() {
    /** 将defaultOptions中的默认值写进options中 */
    Object.entries((this.constructor as typeof XUIElement).defaultOptions).forEach(([key, value]) => {
      if (this.options && this.options[key] == void 0) {
        this.options[key] = value;
      }
    });
  }

  /**
   * LitElement 生命周期：每次更新前调用。
   */
  willUpdate(_changedProperties?: PropertyValues) {
  }

  /**
   * Web Component 生命周期：元素插入 DOM 时调用。
   *
   * 执行以下初始化操作：
   *   1. 调用 super.connectedCallback()（Lit 内部逻辑）
   *   2. 遍历 customEvents 映射，将元素上对应名称的 DOM 属性值作为脚本，
   *      绑定为事件处理函数并通过 addEventListener 注册
   *   3. 如果存在 x-script 属性，立即执行其中的脚本
   *
   * 事件绑定采用 Map 缓存处理函数引用，确保 disconnectedCallback 时能正确移除。
   */
  connectedCallback() {
    super.connectedCallback();
    this.initialize();
    Object.entries((this.constructor as typeof XUIElement).customEvents).forEach(([name]) => {
      if (this.hasAttribute(name) && !this.eventFunctionMap.has(name)) {
        this.eventFunctionMap.set(name, () => {
          XUIElement.execScript(this, this.getAttribute(name));
        });
        this.addEventListener(name, this.eventFunctionMap.get(name), false);
      }
    });

    if (this.hasAttribute('x-script')) {
      XUIElement.execScript(this, this.getAttribute('x-script'));
    }
  }

  /**
   * Web Component 生命周期：元素从 DOM 中移除时调用。
   *
   * 清理 connectedCallback 中注册的事件监听器：
   *   遍历 customEvents 映射，对已绑定的元素属性事件执行 removeEventListener，
   *   并从 eventFunctionMap 中删除对应缓存。
   */
  disconnectedCallback(): void {
    super.disconnectedCallback();
    Object.entries((this.constructor as typeof XUIElement).customEvents).forEach(([name]) => {
      if (this.hasAttribute(name) && this.eventFunctionMap.has(name)) {
        this.removeEventListener(name, this.eventFunctionMap.get(name));
        this.eventFunctionMap.delete(name);
      }
    });
  }
}
