///<reference types="jquery" />

import { util } from './utils.js';

// ── 全局引用 ──────────────────────────────────────────────────────────────────
/** 浏览器端的 axios 实例，用于所有 HTTP 请求（GET 配置 / POST 表单 / 菜单加载等）。 */
const axios = (window as any).axios;

// ── flame namespace ──────────────────────────────────────────────────────────

/**
 * 全局 flame 工具集，挂载于 `window.flame`。
 *
 * 提供以下核心能力：
 * - Grid 组件生命周期管理（加载 / 刷新 / 缓存）
 * - Action 分发（弹窗 / 调用 Processor / 下载 / 执行脚本）
 * - 弹窗与模态窗口管理
 * - 表单提交与校验
 * - 菜单（右键菜单 / 按钮下拉菜单 / Action 菜单）
 * - URL 与样式工具函数
 * - CSRF Token 管理
 *
 * @remarks
 * 该命名空间在 `flame-autoloader.ts` 中作为 ES 模块导出，同时通过 `Object.assign`
 * 挂载到 `window.flame` 上以兼容旧有的全局调用方式。
 */
export namespace flame {

    // ── 属性 ──────────────────────────────────────────────────────────────────

    /**
     * Grid 组件配置缓存。
     *
     * @remarks
     * 键为 `compId`（由 `builder$uid$timestamp` 拼接而成），值为 EasyUI Grid 的
     * 完整配置对象。`loadGrid()` 完成后写入，`getCache()` 通过 gridId → compId
     * 映射查找，用于 Grid 刷新、右键菜单、Action 参数收集等场景。
     */
    export const Cache: Record<string, any> = {};

    /**
     * 日志输出通道，默认使用浏览器 `console`。
     *
     * @remarks
     * 可替换为自定义 logger 以对接统一的日志系统。当前仅在部分错误处理路径中
     * 使用，未来可逐步覆盖 `${logger.debug()}` / `${logger.warn()}` 等调用。
     */
    export let logger: Console = console;

    // ── 上下文路径 ────────────────────────────────────────────────────────────

    /** @internal 存储经由 setter 写入的上下文路径，初始值由 getter 懒计算。 */
    let _ctxPath: string | undefined;

    /**
     * 应用上下文路径。
     *
     * @remarks
     * - 读取时若未显式设置则返回默认值 `"/XWorx"`。
     * - 写入后 `getHREF()` / `popupWindow()` / `actionWindow()` 等方法都会
     *   自动在此路径前拼接，生成完整的应用内 URL。
     * - 通过 `Object.defineProperty` 声明为既可读又可写的属性，兼容
     *   `flame.contextPath = '/myApp'` 和 `const p = flame.contextPath` 两种用法。
     */
    Object.defineProperty(flame, 'contextPath', {
        get(): string { return util.isBlank(_ctxPath) ? '/XWorx' : _ctxPath!; },
        set(v: string) { _ctxPath = v; },
        enumerable: true, configurable: true,
    });

    // ── Cache 管理 ────────────────────────────────────────────────────────────

    /**
     * 根据 gridId 从缓存中查找对应的 Grid 完整配置。
     *
     * 查找流程：
     * 1. 通过 `jQuery('#' + gridId)` 获取 DOM 元素上的 `data-compId` 属性。
     * 2. 以 compId 为键在全局 `Cache` 中查找。
     *
     * @param gridId 目标 Grid 的 DOM 元素 id。
     * @returns 缓存的 Grid 配置对象，若未命中缓存则返回 `undefined`。
     *
     * @see addCache
     */
    export function getCache(gridId: string): any {
        const compId = jQuery("#" + gridId).attr("data-compId");
        return compId ? Cache[compId] : undefined;
    }

    /**
     * 将 Grid 配置写入全局缓存。
     *
     * 在 `loadGrid()` 渲染成功后自动调用，后续刷新、右键菜单、Action 参数
     * 收集均依赖此缓存。
     *
     * @param config Grid 配置对象，必须包含 `compId` 字段。
     */
    export function addCache(config: any): void {
        Cache[config.compId] = config;
    }

    // ── URL / 样式 / 脚本 ─────────────────────────────────────────────────────

    /**
     * 将相对路径拼接 `contextPath` 前缀，生成完整的应用内绝对路径 URL。
     *
     * 拼接规则：
     * - 若 `contextPath` 为空或目标路径已包含 `contextPath` 前缀，直接返回。
     * - 自动处理 `contextPath` 末尾与目标路径开头的 `/` 重复 / 缺失。
     *
     * @param o 相对路径，如 `"XUI$/form/x.y.Z"` 或 `"thymeleaf/util/popup.html"`。
     * @returns 完整的应用内 URL，如 `"/XWorx/XUI$/form/x.y.Z"`。
     */
    export function getHREF(o: string): string {
        const ctx = (flame as any).contextPath as string;
        if (!ctx || ctx == '') {
            return o;
        }
        if (o) {
            const bool = ctx.charAt(ctx.length - 1) == '/';
            if (o.indexOf(ctx) == 0) {
                return o;
            } else if (bool && o.charAt(0) == '/') {
                return ctx + o.substring(1);
            } else if (!(bool || o.charAt(0) == '/')) {
                return ctx + '/' + o;
            } else {
                return ctx + o;
            }
        }
        return o;
    }

    /**
     * 将 CSS 内联样式字符串解析为键值对象。
     *
     * @param style 样式字符串，如 `"width:680px;height:380px;padding:5px"`。
     * @returns 样式对象，如 `{ width: "680px", height: "380px", padding: "5px" }`。
     *
     * @internal 供 `_easyuiWindow` 和 `_applyStyle` 使用。
     */
    function _convertStyle(style: string): Record<string, string> {
        const result: Record<string, string> = {};
        if (!style) {
            return result;
        }
        for (const k in style.split(';')) {
            const value = style.split(';')[k];
            if (value) {
                const _array = value.split(':');
                if (_array.length == 2 && _array[0] && _array[1]) {
                    result[_array[0].trim()] = _array[1].trim();
                }
            }
        }
        return result;
    }

    // ── 参数收集 ──────────────────────────────────────────────────────────────

    /**
     * 收集 Grid Action 执行所需的全部请求参数。
     *
     * 合并优先级（后面的覆盖前面的）：
     * 1. 当前页面 URL 查询参数
     * 2. Grid 配置中的 `queryParams`
     * 3. `compId`（自动注入）
     * 4. Grid 选中行的 `rowIds`（序列化为 JSON 字符串）
     * 5. 调用方传入的额外 params
     *
     * @param config Grid 组件配置对象，可为 `null`。
     * @param params 额外参数（来自 `handleRowAction` / `handleBarAction` 的
     *               rowId 等）。
     * @returns 合并后的参数对象。
     *
     * @internal 由 `_handleAction` 统一调用。
     */
    function _collectParams(config: any, params: any): Record<string, any> {
        const result = util.getURLParameter();
        console.log(result);

        if (config) {
            if (config.queryParams) {
                Object.assign(result, config.queryParams);
            }
            if (config.compId) {
                result['compId'] = config.compId;
            }

            if (config.component) {
                const $el = jQuery('#' + config.gridId) as any;
                let selected: any;
                if (config.component === 'datagrid') {
                    selected = $el.datagrid('getChecked');
                } else if (config.component === 'treegrid') {
                    selected = $el.treegrid('getChecked');
                } else if (config.component === 'propertygrid') {
                    selected = $el.propertygrid('getChecked');
                }
                if (selected && selected.length > 0) {
                    const idField = config.idField || 'rowId';
                    const rowIds = selected.map((row: any) => row[idField]).filter(Boolean);
                    if (rowIds.length > 0) {
                        result['rowIds'] = JSON.stringify(rowIds)
                    }
                }
            }
        }

        if (params) {
            Object.assign(result, params);
        }

        return result;
    }

    // ── Grid Formatter ─────────────────────────────────────────────────────────

    /**
     * 将 Grid Column 配置中的 `formatter` 字符串替换为全局作用域上的函数引用。
     *
     * 背景：EasyUI Grid 通过 AJAX 从后端返回的列配置中，`formatter` 字段只能
     * 是字符串（函数名），无法直接传递函数引用。因此需要在客户端将其解析为
     * `window[formatterName]` 上的实际函数。
     *
     * @param config Grid 组件配置对象（会原地修改）。
     *
     * @internal 在 `loadGrid()` 中自动调用。
     */
    function _handleFormatter(config: any): void {
        if (!config || !config.columns) {
            return;
        }
        for (const i in config.columns) {
            const columns = config.columns[i];
            if (!columns) {
                continue;
            }
            for (const j in columns) {
                const column = columns[j];
                if (util.isBlank(column.formatter)) {
                    continue;
                }
                const func = (window as any)[column.formatter];
                if (func) {
                    column.formatter = func;
                }
            }
        }
    }

    export function iconFormatter(value) {
        if (!value) {
            return '';
        }
        return '<img src="' + value + '" alt="" style="width:16px;height:16px;vertical-align:middle" />';
    }

    // ── Grid 错误告警 ─────────────────────────────────────────────────────────

    /**
     * 拦截 EasyUI Grid 的 `onLoadSuccess` 回调，在服务端返回 `FAILURE` 状态时
     * 自动弹出错误提示。
     *
     * 覆盖三种 Grid 类型：`datagrid` / `treegrid` / `propertygrid`。
     * 原始 `onLoadSuccess` 回调会在成功时（非 FAILURE）被正常调用。
     *
     * @param config Grid 组件配置对象（会原地修改 `onLoadSuccess`）。
     */
    export function alertFailureInfo(config: any): void {
        if (!config) return;
        switch (config.component) {
            case 'datagrid': {
                const orig = config.onLoadSuccess;
                config.onLoadSuccess = function(data: any) {
                    if (data && data.status == 'FAILURE') {
                        alert(data.message);
                    } else if (orig) {
                        orig(data);
                    }
                };
                break;
            }
            case 'treegrid': {
                const orig = config.onLoadSuccess;
                config.onLoadSuccess = function(row: any, data: any) {
                    if (data && data.status == 'FAILURE') {
                        alert(data.message);
                    } else if (orig) {
                        orig(row, data);
                    }
                };
                break;
            }
            case 'propertygrid': {
                const orig = config.onLoadSuccess;
                config.onLoadSuccess = function(row: any, data: any) {
                    if (data && data.status == 'FAILURE') {
                        alert(data.message);
                    } else if (orig) {
                        orig(row, data);
                    }
                };
                break;
            }
        }
    }

    // ── Grid 加载 ─────────────────────────────────────────────────────────────

    /**
     * 通过后端 Builder 名称加载并渲染 EasyUI Grid 组件。
     *
     * **完整调用链：**
     * 1. `axios.get("XUI$/ui/{builder}")` 从后端获取 Grid 配置 JSON。
     * 2. 将配置注入 `compId` / `gridId` / CSRF Token，解析 formatter 和右键菜单。
     * 3. 根据 `config.component` 类型（`datagrid` / `treegrid` / `propertygrid` /
     *    `meshgrid`）调用对应的 jQuery EasyUI 方法渲染到 DOM。
     * 4. 将配置写入 `Cache`，供后续刷新 / Action / 菜单操作使用。
     * 5. 若提供 `onXComplete` 回调，在渲染完成后调用。
     *
     * @param gridId  目标 DOM 容器元素的 id。
     * @param builder 后端 Java Builder 全限定名，
     *                如 `"xw.team.builder.ContainerTeamTreeBuilder"`。
     * @param setting  可选配置：
     *    - `queryParams`   — 查询参数，用于 Grid 数据加载和后续刷新。
     *    - `onXComplete`   — 渲染完成回调 `(config) => void`。
     *    - `onBeforeExpand` — TreeGrid 节点展开前回调。
     *    - … 其他 EasyUI Grid 支持的标准属性。
     *
     * @example
     * ```js
     * flame.loadGrid('myGrid', 'com.example.MyBuilder', {
     *   queryParams: { oid: 'OR:xw.context.Folder:1121' },
     *   onClickRow: function(row) {
     *     console.log('clicked:', row.oid);
     *   }
     * });
     * ```
     */
    export function loadGrid(gridId: string, builder: string, setting: any): void {
        if (setting.queryParams === undefined) {
            setting.queryParams = {};
        }
        Object.assign(setting.queryParams, { gridId: gridId });
        axios.get('XUI$/ui/' + builder, {
            params: setting.queryParams
        }).then(({ data }: any) => {
            if (data === undefined) {
                alert('Server internal error.');
                return;
            }
            if (data.status == 'FAILURE') {
                alert(data.message);
                return;
            }
            const config = data;
            config.remoteSort = false;
            config.gridId = gridId;
            for (const p in setting) {
                if (p != 'onBeforeExpand') {
                    config[p] = setting[p];
                }
            }
            if (config.queryParams === undefined) {
                config.queryParams = {};
            }
            if (config.compId) {
                jQuery('#' + gridId).attr("data-compId", config.compId);
            }
            config.queryParams._csrf = util.getCsrf();
            _handleFormatter(config);
            if (!util.isBlank(config.contextMenu)) {
                config.onContextMenu = function(e: MouseEvent, row: any) {
                    if (!row) {
                        return;
                    }
                    loadContextMenu(config, e, row);
                };
            }
            alertFailureInfo(config);
            switch (config.component) {
                case 'meshgrid':
                    (jQuery('#' + gridId) as any).meshgrid(config);
                    addCache(config);
                    break;
                case 'datagrid':
                    if (config.toolbar) _bindToolbar2Grid(config);
                    (jQuery('#' + gridId) as any).datagrid(config);
                    addCache(config);
                    break;
                case 'treegrid': {
                    if (config.toolbar) _bindToolbar2Grid(config);
                    const _onBeforeExpand = config.onBeforeExpand;
                    config.onBeforeExpand = function(row: any) {
                        config.queryParams.xx_flame_expand_yy = true;
                        if (_onBeforeExpand) {
                            return _onBeforeExpand(row);
                        }
                        return true;
                    };
                    (jQuery('#' + gridId) as any).treegrid(config);
                    addCache(config);
                    break;
                }
                case 'propertygrid':
                    if (config.toolbar) {
                        _bindToolbar2Grid(config);
                    }
                    (jQuery('#' + gridId) as any).propertygrid(config);
                    break;
            }
            if (setting && setting.onXComplete) {
                setting.onXComplete(config);
            }
        }).catch(function(error: any) {
            console.error(error);
        });
        if (!setting) {
            setting = {};
        }
        if (!setting.queryParams) {
            setting.queryParams = {};
        }
    }

    // ── Grid 刷新 ─────────────────────────────────────────────────────────────

    /**
     * 根据 gridId 自动识别 Grid 类型并执行对应的刷新操作。
     *
     * 支持的类型：`datagrid` / `treegrid` / `propertygrid`。
     * 若 gridId 对应的缓存中无配置则静默跳过。
     *
     * @param gridId 目标 Grid 的 DOM 元素 id。
     * @param params 可选的新查询参数，传入后会替换缓存的 `queryParams`。
     */
    export function reloadGrid(gridId: string, params?: any): void {
        const config = getCache(gridId);
        if (!config || !config.component) {
            return;
        }
        const grid = jQuery('#' + config.gridId) as any;

        if (params) {
            config.queryParams = params;
        }
        if (config.queryParams === undefined) {
            config.queryParams = {};
        }
        config.queryParams._csrf = util.getCsrf();

        switch (config.component) {
            case 'datagrid':
                grid.datagrid('clearSelections');
                grid.datagrid(config);
                break;
            case 'treegrid':
                grid.treegrid('clearSelections');
                grid.treegrid(config);
                break;
            case 'propertygrid':
                grid.propertygrid('clearSelections');
                grid.propertygrid(config);
                break;
            default:
                break;
        }
    }

    /**
     * 重新加载 TreeGrid 中指定节点的子节点。
     *
     * @param id    目标 TreeGrid 的 DOM 元素 id。
     * @param rowId 要重新加载的节点 rowId。
     */
    export function reloadNode(id: string, rowId: string): void {
        (jQuery('#' + id) as any).treegrid('reload', rowId);
    }

    // ── 工具栏 ────────────────────────────────────────────────────────────────

    /**
     * 为 Grid 的 toolbar 配置项绑定 `_handleAction` 处理函数。
     *
     * toolbar 配置为数组，每项包含 Action 所需字段（processor / url / winType 等）。
     * 在 `loadGrid()` 渲染前绑定，点击时直接从缓存 Grid 配置中读取上下文。
     *
     * @param config Grid 组件配置对象。
     *
     * @internal 在 `loadGrid()` 中自动调用。
     */
    function _bindToolbar2Grid(config: any): void {
        if (Array.isArray(config.toolbar)) {
            for (const i in config.toolbar) {
                const a = config.toolbar[i];
                config.toolbar[i].handler = function() {
                    _handleAction(a, config);
                };
            }
        }
    }

    // ── 右键菜单 ──────────────────────────────────────────────────────────────

    /**
     * 加载并显示 EasyUI 右键菜单。
     *
     * 在配置了 `contextMenu` 属性的 Grid 中，由 `onContextMenu` 自动调用。
     * 菜单内容从后端 `XUI$/menu/{actionKey}` 接口动态获取。
     *
     * **DOM 结构：**
     * 会在 `#xwx_context_menu_pack` 容器中动态创建菜单 div，避免重复解析。
     * 首次调用时创建容器，后续复用。
     *
     * @param config Grid 组件配置，需包含 `contextMenu` 字段（格式 `"type$name"`）。
     * @param e      鼠标事件对象，用于定位菜单弹出位置。
     * @param row    当前右键所在行数据，其 `oid` 会作为参数传给菜单加载接口。
     */
    export function loadContextMenu(config: any, e: MouseEvent, row: any): void {
        if (!config.contextMenu) {
            return;
        }

        e.preventDefault();
        const identity = '#' + config.contextMenu.replace(/:/g, '\\:');
        let $menu = jQuery(identity);
        if ($menu.length == 0) {
            if (jQuery('#xwx_context_menu_pack').length == 0) {
                jQuery(document.body).append('<div id="xwx_context_menu_pack" style="display:none"></div>');
            }
            jQuery('#xwx_context_menu_pack').append('<div id="' + config.contextMenu + '" class="xui-menu" style="width:60px;"></div>');
            (jQuery as any).parser.parse('#xwx_context_menu_pack');
            $menu = jQuery(identity);
        }
        axios.get('XUI$/menu/' + config.contextMenu.replace(/:/g, '/'), { params: { oid: row.oid } }).then(({ data }: any) => {
            $menu.empty();
            const actions = data.data;
            if (actions && actions.length > 0) {
                for (const a of actions) {
                    ($menu as any).menu('appendItem', { id: a.id, text: a.display, icon: a.icon, iconCls: a.iconCls, wintype: a.winType, onclick: () => {
                        _handleAction(a, config, { oid: row.oid, rowId: row.id });
                    } });
                }
                ($menu as any).menu('show', { left: e.pageX - 10, top: e.pageY - 5, hideOnUnhover: false });
            }
        }).catch(function(error: any) {
            console.error(error);
        });
        e.preventDefault();
    }

    // ── Action 菜单 ───────────────────────────────────────────────────────────

    /**
     * 通过 ActionKey 加载操作菜单（用于信息页"操作"按钮的下拉菜单）。
     *
     * 菜单项从后端 `XUI$/menu/{actionKey}` 接口动态获取，支持带图标的操作项。
     * 点击菜单项时分发到 `_handleAction` 执行。
     *
     * @param actionKey 菜单注册名，格式 `"type$name"` 或 `"type:name"`，
     *                  如 `"com.flame.entity.XPart:XWX-ActionMenu"`。
     * @param oid       当前实体对象的 OID，作为参数传递到菜单加载接口。
     * @param el        触发菜单的 DOM 元素（用于计算弹出位置）。
     */
    export function loadActionMenu(actionKey: string, oid: string, el?: HTMLElement): void {
        const identity = '#' + actionKey.replace(/:/g, '\\:');
        let $menu = jQuery(identity);

        if ($menu.length == 0) {
            let pack = jQuery('#xwx_action_menu_pack');
            if (pack.length == 0) {
                jQuery(document.body).append('<div id="xwx_action_menu_pack" style="display:none"></div>');
                pack = jQuery('#xwx_action_menu_pack');
            } else {
                pack.empty();
            }
            pack.append('<div id="' + actionKey + '" class="xui-menu" style="width:60px;"></div>');
            (jQuery as any).parser.parse('#xwx_action_menu_pack');
            $menu = jQuery(identity);
        }
        axios.get('XUI$/menu/' + actionKey.replace(/:/g, '/'), { params: { oid: oid } }).then(({ data }: any) => {
            $menu.empty();
            const actions = data.data;
            if (actions && actions.length > 0) {
                for (const a of actions) {
                    ($menu as any).menu('appendItem', {
                        id: a.id, text: a.display, icon: a.icon, iconCls: a.iconCls, wintype: a.winType,
                        onclick: () => {
                            _handleAction(a, undefined, { oid: oid, rowId: oid });
                        }
                    });
                }
                if (el) {
                    const r = el.getClientRects()[0];
                    ($menu as any).menu('show', { top: r.top + 22, left: r.left, hideOnUnhover: false });
                }
            }
        }).catch((e: any) => { console.error(e); });
    }

    /**
     * 通过 Processor 名称加载按钮下拉菜单。
     *
     * 与 `loadActionMenu` 的区别：菜单项来源于直接调用 Processor 的返回结果
     * （`XUI$/get/{processor}`），而非菜单注册中心。适用于动态生成菜单项的场景。
     *
     * @param processor 后端 Processor 全限定名。
     * @param oid       当前实体对象的 OID。
     * @param el        触发按钮的 DOM 元素（用于计算弹出位置）。
     */
    export function loadButtonMenu(processor: string, oid: string, el?: HTMLElement): void {
        const rid = util.randomId('xwx_button_menu'), identity = '#' + rid;
        let $menu = jQuery(identity);

        if ($menu.length == 0) {
            let pack = jQuery('#xwx_menu_button_pack');
            if (pack.length == 0) {
                jQuery(document.body).append('<div id="xwx_menu_button_pack" style="display:none"></div>');
                pack = jQuery('#xwx_menu_button_pack');
            } else {
                pack.empty();
            }
            pack.append('<div id="' + rid + '" class="easyui-menu" style="width:60px;"></div>');
            (jQuery as any).parser.parse('#xwx_menu_button_pack');
            $menu = jQuery(identity);
        }
        axios.get('XUI$/get/' + processor, { params: { oid: oid } }).then(({ data }: any) => {
            $menu.empty();
            const actions = data.data;
            if (actions && actions.length > 0) {
                for (const a of actions) {
                    ($menu as any).menu('appendItem', {
                        id: a.id, text: a.display, icon: a.icon, iconCls: a.iconCls, wintype: a.winType,
                        onclick: () => {
                            _handleAction(a, null, {});
                        }
                    });
                }
                if (el) {
                    const r = el.getClientRects()[0];
                    ($menu as any).menu('show', { top: r.top + 22, left: r.left, hideOnUnhover: false });
                }
            }
        }).catch((e: any) => { console.error(e); });
    }

    // ── 处理器调用 ────────────────────────────────────────────────────────────

    /**
     * 向指定 Processor 发起 POST 请求（用于 `invoke` 类型 Action）。
     *
     * @param processor 后端 Processor 全限定名，如 `"xw.team.processor.AddTeamUserProcessor"`。
     * @param params    请求体参数（由 `_collectParams` 组装）。
     * @param callback  成功回调，接收 `result` 对象。
     *
     * @internal
     */
    function _invokeProcessor(processor: string, params: any, callback?: any): void {
        jQuery.post(getHREF('XUI$/form/' + processor), params, callback);
    }

    /**
     * 向指定 Processor 发起文件下载请求。
     *
     * @param processor 后端 Processor 全限定名。
     * @param params    请求体参数。
     * @param callback  下载完成回调（通常为空函数）。
     *
     * @internal
     */
    function _downloadProcessor(processor: string, params: any, callback?: any): void {
        jQuery.post(getHREF('XUI$/download/' + processor), params, callback);
    }

    // ── Action 分发 ───────────────────────────────────────────────────────────

    /**
     * **Bar Action 入口**——这是外部最常用的 Grid 工具栏按钮点击分发点。
     *
     * 委托 `_handleAction` 根据 Action 配置执行相应操作（弹窗 / 调用 Processor /
     * 下载 / 执行脚本）。
     *
     * @param action  Action 配置对象，至少包含 `winType`，可选 `url` / `processor` /
     *                `onclick` / `beforeJS` / `afterJS` / `style` / `display` 等。
     * @param config  可选，Grid 组件配置对象（用于参数收集和成功后刷新）。
     * @param params  可选，附加查询参数（与 `_collectParams` 合并）。
     *
     * @example
     * ```js
     * flame.handleBarAction({
     *   winType: 'popup',
     *   url: 'thymeleaf/team/addTeamUser.html',
     *   processor: 'xw.team.processor.AddTeamUserProcessor',
     *   style: 'width:680px;height:500px'
     * }, gridConfig);
     * ```
     */
    export function handleBarAction(action: any, config?: any, params?: any): void {
        if (!action) {
            return;
        }

        _handleAction(action, config, params);
    }

    /**
     * **行 Action 入口**——供 ActionBox 等行内操作组件调用。
     *
     * 若 `action.compId` 存在，会从全局 {@link Cache} 中查找对应的 Grid 配置
     * 并通过 {@link _collectParams} 收集选中行参数，合并到提交参数中。
     *
     * **分发逻辑（由 {@link _handleAction} 执行）：**
     * - `popup`    → 弹出 EasyUI Window。
     * - `invoke`   → 调用 Processor 并在成功后自动刷新 Grid。
     * - `download` → 调用下载 Processor。
     * - `script`   → 通过 `runScript` 执行 `action.onclick`。
     *
     * @param action Action 配置对象，至少包含 `winType`。
     *               可选 `compId` 用于从 Cache 中查找 Grid 配置。
     * @param rowId  当前行 rowId，将作为 `rowId` 字段传递给 Processor。
     *
     * @example
     * ```js
     * // ActionBox 渲染的 HTML 中：
     * // onclick="flame.handleRowAction(actionConfig, 'OR:xw.container.Folder:12345')"
     * ```
     */
    export function handleRowAction(action: any, rowId: string): void {
        if (!action || !rowId) {
            return;
        }

        let config: any = {};
        if (action.compId) {
            config = Object.values(Cache).find((c: any) => c.compId === action.compId) || null;
        }
        _handleAction(action, config, { rowId: rowId });
    }

    /**
     * **Action 核心分发器。**
     *
     * 根据 Action 的 `winType` 字段分发到不同的执行路径：
     *
     * | winType   | 行为                                      |
     * |-----------|-------------------------------------------|
     * | `popup`   | 调用 `_easyuiWindow` 弹出模态窗口。          |
     * | `invoke`  | POST 表单到 Processor，成功后自动刷新 Grid。 |
     * | `download`| POST 下载请求。                             |
     * | `script`  | 通过 `runScript` 执行配置中的 onclick 脚本。 |
     * | 其他      | 仅执行 beforeJS / afterJS 脚本。            |
     *
     * 执行前后会分别调用 `action.beforeJS` 和 `action.afterJS` 脚本
     * （通过 `runScript`），`beforeJS` 返回 `false` 则中止后续流程。
     *
     * @param action Action 配置对象，核心字段为 `winType`。
     * @param config Grid 组件配置对象（用于参数收集和成功后刷新）。
     * @param params 额外参数（如 `{ rowId: '...' }` 或 `{ oid: '...' }`）。
     *
     * @internal 由 `handleBarAction` / `handleRowAction` / Grid 工具栏 /
     *           右键菜单 / Action 菜单统一调用。
     */
    function _handleAction(action: any, config: any, params?: any): void {
        const p = _collectParams(config, params);
        switch (action.winType) {
            case 'popup': {
                if (util.runScript(action.beforeJS, p)) {
                    _easyuiWindow(action, p);
                    util.runScript(action.afterJS, p);
                }
                break;
            }
            case 'invoke': {
                if (util.runScript(action.beforeJS, p)) {
                    _invokeProcessor(action.processor, p, (result: any) => {
                        if (result) {
                            if (result.status == 'SUCCESS') {
                                (jQuery as any).messager.alert('成功', result.message, 'info');

                                if (config) {
                                    reloadGrid(config.gridId, config.queryParams);
                                }
                            } else if (result.status == 'FAILURE') {
                                (jQuery as any).messager.alert('错误', result.message, 'error');
                            }
                        }
                    });
                    util.runScript(action.afterJS, p);
                }
                break;
            }
            case 'download': {
                if (util.runScript(action.beforeJS, p)) {
                    _downloadProcessor(action.processor, p, () => {});
                    util.runScript(action.afterJS, p);
                }
                break;
            }
            case 'script': {
                if (util.runScript(action.beforeJS, p)) {
                    util.runScript(action.onclick, p);
                    util.runScript(action.afterJS, p);
                }
                break;
            }
            default: {
                if (util.runScript(action.beforeJS, p)) {
                    util.runScript(action.afterJS, p);
                }
                break;
            }
        }
    }

    // ── 公共 API：带拦截的 Processor 调用 ─────────────────────────────────────

    /**
     * 带 `before` 拦截函数的 Processor 调用。
     *
     * 与 `_handleAction('invoke')` 的区别：不依赖 Grid 缓存和自动刷新，
     * 适合在非 Grid 场景下直接调用 Processor。
     *
     * @param processor 后端 Processor 全限定名。
     * @param params    请求体参数。
     * @param before    可选的前置校验回调，接收参数对象 `_params`，
     *                  可在提交前修改参数；返回 `false` 则中止提交。
     * @param callback  可选的成功回调，接收 `result` 对象。
     */
    export function submitProcessor(processor: string, params: any, before?: any, callback?: any): void {
        const _params: Record<string, any> = {};

        if (before && !before(_params)) {
            return;
        }
        if (params) {
            Object.assign(_params, params);
        }
        _invokeProcessor(processor, _params, callback);
    }

    // ── 弹窗 ──────────────────────────────────────────────────────────────────

    /**
     * 根据 Action 配置打开 EasyUI Window 弹窗。
     *
     * **URL 处理逻辑：**
     * - 若 `btnItem.key` 为空，使用 `btnItem.url` 作为路径，JSP 文件特殊处理。
     * - 若 `btnItem.key` 不为空，通过 `XUI$/action/{key}` 加载。
     * - 所有路径经 `getHREF` 添加 contextPath 前缀。
     *
     * **尺寸解析：**
     * - 从 `btnItem.style`（CSS 字符串）中提取 `width` / `height`。
     * - `height` 支持百分比（如 `"80%"`），按窗口高度换算。
     *
     * **关键行为：**
     * - 若 `params` 中尚未包含 `processor`，自动将 `action.processor` 注入，
     *   确保弹窗内 `popup.html` 的 `${commandBean.processor}` 表达式正常渲染。
     *
     * @param btnItem Action 配置对象，包含 `url` / `style` / `text` / `key` / `processor`。
     * @param params  查询参数对象，由 `_collectParams` 组装后传入。
     *
     * @internal 由 `_handleAction('popup')` 调用。
     */
    function _easyuiWindow(btnItem: any, params: any): void {
        let xuiWin = jQuery('#xx_flame_win_yy');
        if (xuiWin.length == 0) {
            jQuery(document.body).append('<div id="xx_flame_win_yy" style="width:400px;height:300px"></div>');
            xuiWin = jQuery('#xx_flame_win_yy');
        }
        let width: any = '400px', height: any = '300px';
        if (btnItem.style) {
            const s = _convertStyle(btnItem.style);
            if (s['width']) {
                width = s['width'];
            }
            if (s['height']) {
                height = s['height'];
            }
            xuiWin.attr('style', 'top:10px;' + btnItem.style);
        } else {
            xuiWin.attr('style', 'top:10px;');
        }
        let href = btnItem.url;
        if (util.isBlank(btnItem.key)) {
            if ((href as any).endWith('.jsp') || href.indexOf('.jsp?') > 0) {
                href = href.substr(0, 1) == '/' ? getHREF(href.substr(1)) : getHREF(href);
            } else {
                href = getHREF(href);
            }
        } else {
            href = getHREF('XUI$/action/' + btnItem.key);
        }
        if (height && typeof height === 'string' && height.endsWith('%')) {
            height = jQuery(window).height()! * parseFloat(height) / 100;
        }
        // 将 processor 注入 queryParams，确保 popup.html 的 commandBean.processor 不为空
        if (params && btnItem.processor && !params.processor) {
            params.processor = btnItem.processor;
        }
        (xuiWin as any).window({ title: btnItem.text, href, model: true, inline: false, width, height, minimizable: false, queryParams: params }).window('hcenter').window('resize');
    }

    // ── 窗口打开器 ────────────────────────────────────────────────────────────

    /**
     * 确保全局弹窗容器 div 存在，不存在则动态创建。
     *
     * @param id 容器 div 的 id，默认为 `"xx_flame_win_yy"`。
     * @returns 对应元素的 jQuery 对象。
     *
     * @internal
     */
    function _ensureWinDiv(id?: string): any {
        const eid = id || 'xx_flame_win_yy';
        let w = jQuery('#' + eid);

        if (w.length == 0) {
            jQuery(document.body).append('<div id="' + eid + '" style="width:400px;height:300px"></div>');
            w = jQuery('#' + eid);
        }
        return w;
    }

    /**
     * 解析 CSS 样式字符串并应用到弹窗容器，同时返回解析后的宽高。
     *
     * @param w     弹窗容器 jQuery 对象。
     * @param style CSS 内联样式字符串，如 `"width:680px;height:500px;"`。
     * @returns `{ width, height }` 对象，单位可能为 `"px"` 或 `"%"`。
     *
     * @internal
     */
    function _applyStyle(w: any, style?: string): { width: any; height: any } {
        let width: any = '400px', height: any = '300px';
        if (style) {
            const s = _convertStyle(style);
            if (s['width']) {
                width = s['width'];
            }
            if (s['height']) {
                height = s['height'];
            }
            w.attr('style', 'top:10px;' + style);
        } else {
            w.attr('style', 'top:10px;');
        }
        return { width, height };
    }

    /**
     * 通过 ActionKey 打开一个弹窗。
     *
     * @param actionKey Action 注册 key。
     * @param title     窗口标题。
     * @param style     CSS 样式字符串，控制窗口尺寸和样式。
     * @param params    查询参数，会经过 `_collectParams` 合并。
     */
    export function actionWindow(actionKey: string, title: string, style: string, params: any): void {
        popupWindow(title, getHREF('XUI$/popup/' + actionKey), style, params);
    }

    /**
     * 通过 URL 或 ActionKey 打开一个弹窗。
     *
     * - 若 `actionKey` 为空，使用 `href` 参数作为加载 URL。
     * - 若 `actionKey` 非空，通过 `XUI$/popup/{actionKey}` 路由加载。
     *
     * @param actionKey 可选，Action 注册 key（为空时使用 href）。
     * @param href      加载的 URL 路径（`actionKey` 为空时生效）。
     * @param title     窗口标题。
     * @param style     CSS 样式字符串。
     * @param params    查询参数，会经过 `_collectParams` 合并。
     */
    export function popupWindow(title: string, href: string, params: any, style: string): void {
        const w = _ensureWinDiv();
        const { width, height } = _applyStyle(w, style);

        (w as any).window({ title, href, model: true, inline: false, width, height, minimizable: false, queryParams: _collectParams(null, params) }).window('hcenter');
    }

    /**
     * 打开一个简单的模态窗口。
     *
     * 与 `_easyuiWindow` 的区别：不支持 `beforeJS` / `afterJS`，直接按给定的
     * URL 和参数打开窗口，不经过 `_handleAction` 分发。
     *
     * @param title 窗口标题。
     * @param href  加载的 URL。
     * @param param 查询参数对象。
     * @param style 可选，CSS 样式字符串，如 `"width:680px;height:500px"`。
     */
    export function openWindow(title: string, href: string, param: any, style?: string): void {
        const w = _ensureWinDiv('xx_flame_win_yy_a');

        if (util.isBlank(style)) {
            w.attr('style', 'top:10px;width:400px;height:300px;');
        } else {
            _applyStyle(w, style);
        }
        (w as any).window({ title, href, model: true, collapsible: false, minimizable: false, maximizable: false, queryParams: param }).window('hcenter');
    }

    /**
     * 在新浏览器标签页打开详情页面。
     *
     * 阻止默认事件和冒泡，使用 `window.open()` 在新标签页打开。
     *
     * @param event 触发事件的鼠标事件对象。
     * @param url   要打开的 URL。
     */
    export function openDetailsPage(event: MouseEvent, url: string): void {
        if (event.preventDefault) {
            event.preventDefault();
        }
        window.open(url);

        if (event.stopPropagation) {
            event.stopPropagation();
        } else {
            (event as any).cancelBubble = true;
        }
    }

    /**
     * 在模态窗口中打开对话框页面。
     *
     * 委托 `openWindow` 创建模态窗口，同时阻止事件冒泡。
     *
     * @param event 触发事件的鼠标事件对象。
     * @param title 窗口标题。
     * @param url   加载的 URL。
     * @param style CSS 样式字符串。
     */
    export function openDialogPage(event: MouseEvent, title: string, url: string, style: string): void {
        if (event.preventDefault) {
            event.preventDefault();
        }
        openWindow(title, url, {}, style);
        if (event.stopPropagation) {
            event.stopPropagation();
        } else {
            (event as any).cancelBubble = true;
        }
    }

    // ── 校验 ──────────────────────────────────────────────────────────────────

    /**
     * Grid 选中行校验：确保至少选中一行，并可限制单选。
     *
     * @param p    `_collectParams` 输出的参数对象（含 `oids` / `rowIds` 字段）。
     * @param bool 为 `true` 时强制单选（多于一条则提示并返回 `false`）。
     * @returns 校验通过返回 `true`，未选中或不符合单选限制时 `alert` 并返回 `false`。
     */
    export function validateSelect(p: any, bool?: boolean, msg?: string): boolean {
        if (p) {
            if (!p.oids && !p.rowIds) {
                if (msg) {
                    alert(msg);
                } else {
                    alert('请选中数据!');
                }
                return false;
            }
            if (bool) {
                if (p.oids && p.oids.length > 1) {
                    alert('只能够勾选一条数据!');
                    return false;
                }
                if (p.rowIds) {
                    const ids = JSON.parse(p.rowIds);
                    if (ids.length > 1) {
                        alert('只能够勾选一条数据!');
                        return false;
                    }
                }
            }
        }
        return true;
    }

    // ── Grid 辅助 ─────────────────────────────────────────────────────────────

    /**
     * 检查指定 `name` 属性的表单元素是否有值（值为空时返回 `true`）。
     *
     * @param name 表单元素的 `name` 属性值。
     * @returns 值为空（null / undefined / 空字符串）时返回 `true`。
     *
     * @remarks
     * 命名看似反直觉（`hasValue` 但空时返回 true），实际与 EasyUI 校验机制配合使用。
     * 其调用了 `util.isBlank`，因此空值返回 `true`。
     */
    export function hasValue(name: string): boolean {
        return util.isBlank(jQuery("[name='" + name + "']").val());
    }

    /**
     * 检查指定 `name` 属性的 checkbox / radio 是否有选中项。
     *
     * @param name 表单元素的 `name` 属性值。
     * @returns 无选中项时返回 `true`。
     *
     * @remarks
     * 同上——调用 `util.isBlank`，无选中时返回 `true`。命名是为了一致性，
     * 实际语义是"是否未选中"。
     */
    export function hasChecked(name: string): boolean {
        return util.isBlank(jQuery("[name='" + name + "']:checked").val());
    }

    /**
     * 打开国际化（Localization）编辑窗口。
     *
     * 支持两种调用方式：
     * - 传入 OID 字符串 → 直接编辑该实体的翻译。
     * - 传入元素 id → 从该元素的值中读取 OID 再编辑。
     *
     * @param o OID 字符串或 DOM 元素 id。
     */
    export function setLocalization(o: any): void {
        if (util.isBlank(o)) {
            return;
        }

        if (util.isOid(o)) {
            openWindow('Localization', 'thymeleaf/localize/setLocalization.html?processor=com.flame.localize.LocalizationProcessor', { oid: o });
        } else {
            const oid = jQuery('#' + o).val();
            if (util.isOid(oid)) {
                openWindow('Localization', 'thymeleaf/localize/setLocalization.html?processor=com.flame.localize.LocalizationProcessor', { oid: oid });
            }
        }
    }

    /**
     * 关闭触发元素所在的 EasyUI 弹窗。
     *
     * 通过 jQuery 向上查找 `.window-body` 父元素并调用 `window('close')`。
     *
     * @param o 触发元素的 DOM 引用或 jQuery 选择器。
     */
    export function closeWindow(o: any): void {
        const p = jQuery(o).parents('.window-body');
        if (p.length > 0) {
            (p as any).window('close');
        }
    }

    // ── 表单提交 ──────────────────────────────────────────────────────────────

    /**
     * **弹窗表单提交入口**——由 `popup.html` 的"完成"按钮调用。
     *
     * **完整流程：**
     * 1. 禁用提交按钮（防重复点击）。
     * 2. 调用 `before` 校验函数，返回 `false` 则中止并恢复按钮。
     * 3. 设置表单 `action` 为 `XUI$/form/{processor}`，以 AJAX 方式提交。
     * 4. **FAILURE** → 通过 `jQuery.messager.alert('error', ...)` 显示错误消息。
     * 5. **SUCCESS** → 调用 `callback`；若回调显式返回 `false` 则保持窗口不关闭；
     *    否则自动关闭弹窗。同时自动刷新关联的 Grid（通过 `compId` 定位）。
     * 6. 恢复提交按钮。
     *
     * @param el        触发按钮的 DOM 元素。
     * @param processor  后端 Processor 全限定名（可选，若为空则仅关闭窗口）。
     * @param callback   提交成功回调 `(result: any) => void | false`。
     *                   返回 `false` 阻止窗口自动关闭。
     * @param before     提交前校验函数名（全局函数名字符串）或函数引用。
     *                   返回 `false` 阻止提交。
     *
     * @example
     * ```html
     * <!-- popup.html 中的"完成"按钮 -->
     * <a href="javascript:void(0)" class="easyui-linkbutton" th:onclick="flame.submitForm(this, 'xw.team.processor.AddTeamRoleProcessor', refreshTeamTree, validateRoleSelection)">完成</a>
     * ```
     */
    export function submitForm(el: HTMLElement, processor?: string, callback?: string | Function, before?: string | Function): void {
        const elBtn = jQuery(el) as any;
        if (elBtn.hasClass('l-btn')) {
            elBtn.linkbutton('disable');
        }

        if (typeof before === 'function') {
            if (!before(el)) {
                if (elBtn.hasClass('l-btn')) {
                    elBtn.linkbutton('enable');
                }
                return;
            }
        } else if (typeof before === 'string') {
            const f = util.getFunction(before);
            if (f && !f(el)) {
                if (elBtn.hasClass('l-btn')) {
                    elBtn.linkbutton('enable');
                }
                return;
            }
        }

        const actionForm = jQuery(el).parents('form').eq(0) as any;
        if (util.isBlank(processor)) {
            const p = elBtn.parents('.window-body').eq(0) as any;
            if (p.length > 0) {
                p.window('close');
            }
            return;
        }

        if (processor && ((processor as any).startWith('XUI$/') || (processor as any).startWith('/XUI$/'))) {
            actionForm.attr('action', getHREF(processor));
        } else {
            actionForm.attr('action', getHREF('XUI$/form/' + processor));
        }
        actionForm.attr('method', 'POST');

        actionForm.form('submit', {
            onSubmit: function(this: any): boolean {
                const $t = jQuery(this) as any;
                const v = $t.form('enableValidation').form('validate');
                if (!v && elBtn.hasClass('l-btn')) {
                    elBtn.linkbutton('enable');
                }
                return v;
            },
            success: function(result: any): void {
                if (typeof result === 'string') {
                    result = jQuery.parseJSON(result);
                }
                if (result.status === 'FAILURE') {
                    (jQuery as any).messager.alert('error', result.message, 'error');
                    if (elBtn.hasClass('l-btn')) {
                        elBtn.linkbutton('enable');
                    }
                } else {
                    let closeWin = true;
                    if (typeof callback === 'function') {
                        if (callback(result) == false) closeWin = false;
                    } else if (typeof callback === 'string') {
                        const f = util.getFunction(callback);
                        if (f && f(result) == false) {
                            closeWin = false;
                        }
                    }
                    if (closeWin) {
                        const p = elBtn.parents('.window-body').eq(0) as any;
                        if (p.length > 0) {
                            p.window('close');
                        }
                    }
                    const compId = jQuery('#compId').val() as string;
                    if (compId) {
                        const ps = compId.split('$');
                        if (ps[0] === 'treegrid') {
                            (jQuery('#' + ps[1]) as any).treegrid('reload', jQuery('#rowId').val());
                        } else if (ps[0] === 'datagrid') {
                            (jQuery('#' + ps[1]) as any).datagrid('reload', jQuery('#rowId').val());
                        }
                    }
                }
                if (elBtn.hasClass('l-btn')) {
                    elBtn.linkbutton('enable');
                }
            },
        } as any);
    }

    // ── MeshGrid 初始化 ───────────────────────────────────────────────────────

    /**
     * 初始化 EasyUI 扩展组件（meshgrid）及全局补丁。
     *
     * 在模块加载时由 `flame-autoloader.ts` 自动调用一次。
     *
     * **包含的补丁和扩展：**
     *
     * 1. **Loading 遮罩清理** — 页面解析完成后移除 `#Loading` 元素。
     * 2. **DataGrid 编辑器扩展** — 新增 `addEditor` / `removeEditor` 方法，
     *    支持运行时动态增删行编辑器。
     * 3. **ComboBox 默认值** — 设为不可编辑、面板高度自适应。
     * 4. **DateBox 解析器** — 覆盖默认 parser，安全处理非法日期字符串。
     * 5. **MeshGrid 组件注册** — 实现基于表单布局（fieldset / table）的
     *    网格表单组件，支持标签对齐、CSRF 注入等。
     *
     * @param $ jQuery 实例（通常为全局 `jQuery`）。
     */
    export function initMeshGird($: any): void {
        $.parser.onComplete = function() {
            if ($('#Loading')) $('#Loading').remove();
        };

        $.extend($.fn.datagrid.methods, {
            addEditor: function(jq: any, param: any) {
                if (param instanceof Array) {
                    $.each(param, function(_i: any, item: any) { $(jq).datagrid('getColumnOption', item.field).editor = item.editor; });
                } else {
                    $(jq).datagrid('getColumnOption', param.field).editor = param.editor;
                }
            },
            removeEditor: function(jq: any, param: any) {
                if (param instanceof Array) {
                    $.each(param, function(_i: any, item: any) {
                        $(jq).datagrid('getColumnOption', item).editor = {};
                    });
                } else {
                    $(jq).datagrid('getColumnOption', param).editor = {};
                }
            },
        });

        $.extend($.fn.combobox.defaults, { editable: false, panelHeight: 'auto', panelMaxHeight: 400 });

        $.fn.datebox.defaults.parser = function(s: string) {
            const t = Date.parse(s);
            return !isNaN(t) ? new Date(t) : new Date();
        };

        const getCookie = function(key: string) {
            const m = document.cookie.match(new RegExp(key + '=([^;]+)'));
            return m && m[1];
        };

        $.fn.meshgrid = function(config: any, params: any) {
            const $this = this;
            if (typeof config == 'string') {
                return ($.fn.meshgrid as any).methods[config](this, params);
            }
            config = config || {};
            this.each(function(this: any) {
                const state = $.data($this, 'meshgrid');
                if (state) {
                    $.extend(state.options, config);
                } else {
                    $.data($this, 'meshgrid', { options: $.extend({}, $.fn.meshgrid.defaults, ($.fn.meshgrid as any).parseOptions(this), config) });
                }
            });

            const tabletConfigs: Array<{id: string, tablet: string}> = [];
            const el = $('#' + config.gridId);
            if (util.isBlank(el)) {
                return;
            }
            el.attr('action', config.url);

            let html = '';
            if (config.hiddens) {
                config.hiddens.forEach(function(hidden: any) {
                    html += hidden;
                });
            }
            config.grids.forEach((grid: any) => {
                if (grid.fieldSet) {
                    html += '<fieldset id="' + grid.id + '" class="' + (util.isBlank(grid.domClass) ? 'xui-fieldset' : grid.domClass) + '">';
                    html += '<legend>' + grid.display + '</legend>';
                    html += '<input type="hidden" name="_csrf" value="' + getCookie('XSRF-TOKEN') + '">';
                    if (!util.isBlank(grid.beforeHTML)) {
                        html += grid.beforeHTML;
                    }
                } else {
                    html += '<div id="' + grid.id + '">';
                    html += '<input type="hidden" name="_csrf" value="' + getCookie('XSRF-TOKEN') + '">';
                }

                const placeHolder = 'data-placeHolder="' + grid.id + '"';
                html += '<table class="xui-form" ' + placeHolder + '">';
                for (let i = 0; i < grid.rowCount; i++) {
                    const row = grid.rows[i];
                    html += '<tr>';
                    for (let j = 0; j < grid.cellCount; j++) {
                        const len = row.cells.length;
                        if (len <= j) {
                            break;
                        }

                        const cell = row.cells[j];
                        if ('Widget' === cell.uiType) {
                            html += '<td class="xui-attribute-gap"></td><td>';
                            // 第一个 widget 放在当前 td 中
                            if (cell.label) {
                                html += cell.label;
                            }
                            html += '</td>';
                            // 其余 widget 放在第二个 td 中
                            if (cell.widgets) {
                                html += '<td';
                                if (cell.colspan && cell.colspan > 1) {
                                    html += " colspan='" + ((cell.colspan - 1) * 3 + 1) + "'";
                                }
                                if (util.isBlank(cell.style)) {
                                    html += " style='white-space:nowrap;padding:1px;'";
                                } else {
                                    html += " style='white-space:nowrap;padding:1px;" + cell.style + "'";
                                }
                                html += '>';
                                for (let k = 0; k < cell.widgets.length; k++) {
                                    html += cell.widgets[k];
                                }
                                html += '</td>';
                            }
                        } else if ('Tablet' === cell.uiType) {
                            const tabletId = cell.value.replace(/\./g, '_');
                            html = html.replace(placeHolder, 'style="width:100%;height:100%"');
                            const tdStyle = util.isBlank(cell.style) ? 'width:100%;height:400px;' : cell.style;
                            html += '<td style="' + tdStyle + '">';
                            html += '<div id="' + tabletId + '" style="width:100%;height:100%;"></div>';
                            tabletConfigs.push({id: tabletId, tablet: cell.value});
                            html += '</td>';
                        }
                    }
                    html += '</tr>';
                }
                html += '</table>';
                if (grid.fieldSet) {
                    if (!util.isBlank(grid.afterHTML)) {
                        html += grid.afterHTML;
                    }
                    html += '</fieldset>';
                } else {
                    html += '</div>';
                }
            });
            (this as any).append(html);
            const self = this;
            tabletConfigs.forEach(function(config) {
                const panel = $(self).closest('x-panel');
                const container = panel.length ? panel : $('body');
                const params: Record<string, any> = {};
                container.find('input[name]').each(function(this: any) {
                    const name = $(this).attr('name');
                    if (name) {
                        params[name] = $(this).val();
                    }
                });
                flame.loadGrid(config.id, config.tablet, {
                    queryParams: params
                });
            });
            $.parser.parse('#' + config.gridId);
            (this as any).meshgrid('alignLabel', this);
        };
        $.fn.meshgrid.defaults = {};
        ($.fn.meshgrid as any).parseOptions = function(this: any, _target: any) {};
        ($.fn.meshgrid as any).methods = {
            alignLabel: function(target: any) {
                const state = $.data(target, 'meshgrid');
                state.options.grids.forEach(function(grid: any) {
                    if (grid.alignLabel) {
                        let xEl: any;
                        if (grid.fieldSet) {
                            xEl = $(target).find('fieldset[id=' + grid.id + ']');
                        } else {
                            xEl = $(target).find('div[id=' + grid.id + ']');
                        }

                        const labels = xEl.find('label.xui-form-label');
                        let maxWidth = -1;
                        for (const label of labels) {
                            if (label.clientWidth > maxWidth) {
                                maxWidth = label.clientWidth;
                            }
                        }
                        if (maxWidth > 0) {
                            for (const label of labels) {
                                $(label).width(maxWidth + 1);
                            }
                        }
                    }
                });
            },
        };
        $.parser.plugins.push('meshgrid');
    }

} // end namespace flame
