import { css } from 'lit';
import componentStyles from '../../styles/component.styles';

export default css`
  ${componentStyles}
  .x-root {
    display: flex;
    flex-direction: column;
    align-items: center;
    overflow: hidden;
    cursor: pointer;
  }
  .x-root:hover {
    background: linear-gradient(180deg, #c6f88d92, #c6f88d50, #c6f88d92);
  }
  .x-root > button {
    display: flex;
    justify-content: center;
    align-items: center;
    background: none;
    cursor: inherit;
  }
  .none {
    border: none;
  }
  .fillet {
    border-radius: 5px !important;
    border: 1px solid #78c6eb !important;
  }
  .square {
    border: 1px solid #78c6eb !important;
  }
  .ellipse {
    border-radius: 10px !important;
    border: 1px solid #78c6eb !important;
  }
  .caret-down:before {
    font-size: 14px;
    filter: invert(60%);
    content: '\\f0d7';
  }
`;
