import { CSSResult, html } from 'lit';
import { util } from '../../internal/utils.js';
import XPanel from './panel.component.js';
import styles from './drag-panel.style.js';

export default class XDragPanel extends XPanel {
  static styles: CSSResult = styles;
  static defaultOptions = { park: 'top', draggable: true, header: { height: 24 }, footer: { height: 0 }, closable: false, border: false };

  public dragPanel(e: MouseEvent) {
    if (!this.options.draggable) return;

    const win = this as HTMLElement;
    const mask = this.getMask();
    const width = this.offsetWidth;
    const height = this.offsetHeight;
    let init_left = e.clientX; //鼠标相对触发事件元素左边的距离
    let init_top = e.clientY;
    let pos = { x: init_left, y: init_top };
    //判断窗口是否移动中,否则会出现点击header就出现窗口大小改变
    let hasMove = false;
    let overflow = this.style.overflow;

    const omm = document.onmousemove;
    const omu = document.onmouseup;
    try {
      //绑定移动事件
      document.onmousemove = (o: MouseEvent) => {
        e.preventDefault();
        hasMove = true;
        //:host定义overflow:auto,拖动时会导致出现滚动条;
        //:host定义overflow:visible,会导致resize:both失效(拖动改变窗口大小);
        //drag/drop窗口时,需要动态切换:host中定义的overflow的值;
        this.setHostStyle({ overflow: 'visible' });

        //通常情况下,e.target指向的是mask div,有时候也也有例外
        pos = {
          x: o.clientX - init_left,
          y: o.clientY - init_top,
        };
        //设置mask的left和top
        util.setStyle(mask, {
          left: mask.clientLeft + pos.x + 'px', //
          top: mask.clientTop + pos.y + 'px',
          width: width + 'px',
          height: height + 'px',
          visibility: 'visible',
        });
      };
      e.preventDefault();
    } finally {
      document.onmouseup = () => {
        if (hasMove) {
          let leftX = win.offsetLeft + pos.x;
          let topY = win.offsetTop + pos.y;
          //设置不能超出左上角
          util.setStyle(win, { left: (leftX < 0 ? 0 : leftX) + 'px', top: (topY < 0 ? 0 : topY) + 'px' });
          //隐藏mask
          util.setStyle(mask, { left: '0px', top: '0px', width: '0px', height: '0px', visibility: 'hidden' });
          //恢复x-window的最初的overflow
          this.setHostStyle({ overflow: overflow });
        }
        document.onmousemove = omm;
        document.onmouseup = omu;
      };
    }
  }

  protected _uiFooter() {
    return html`<slot name="footer"></slot>`;
  }
}
